module.render:
const color = args.color || '#111827';
const body = (content || '').trim();
const notch = String(args.notch) !== 'false';
const shadow = String(args.shadow) !== 'false';
const w = parseInt(args.width, 10);
const width = Number.isFinite(w) ? Math.max(120, Math.min(600, w)) : 240;
const screen = (args.screen && String(args.screen).trim()) || '#fff';
const cls = 'mdp-mod-phone' + (shadow ? '' : ' mdp-ph-noshadow');
return `\n\n<div class="${cls}" style="--ph-color:${color}; --ph-width:${width}px; --ph-screen:${screen};">${notch ? '<div class="mdp-ph-notch"></div>' : ''}<div class="mdp-ph-screen">\n\n${body}\n\n</div></div>\n\n`;
